import{_ as l,c as r,o as t,a5 as i,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.13：桌面版会话分叉、搜索跟随符号链接","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.13.md","filePath":"changelog/v1.1.13.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.1.13.md"};function o(s,e,d,h,p,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="v1-1-13-桌面版会话分叉、搜索跟随符号链接" tabindex="-1">v1.1.13：桌面版会话分叉、搜索跟随符号链接 <a class="header-anchor" href="#v1-1-13-桌面版会话分叉、搜索跟随符号链接" aria-label="Permalink to “v1.1.13：桌面版会话分叉、搜索跟随符号链接”">​</a></h1><p><strong>发布日期</strong>：2026年1月11日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让桌面版支持<strong>会话分叉</strong>，ripgrep 搜索<strong>默认跟随符号链接</strong>，并修复了多个 UI 问题。</p><hr><h2 id="新功能-桌面版会话分叉" tabindex="-1">新功能：桌面版会话分叉 <a class="header-anchor" href="#新功能-桌面版会话分叉" aria-label="Permalink to “新功能：桌面版会话分叉”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面应用现在支持从任意消息点<strong>分叉会话</strong>，创建新的对话分支。这意味着你可以：</p><ul><li>从某个关键节点尝试不同的方向</li><li>保留原有对话的同时探索新思路</li><li>对比不同方案的效果</li></ul><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>在桌面应用中：</p><ol><li>找到你想要分叉的消息</li><li>右键点击该消息</li><li>选择 <strong>Fork Session</strong></li><li>新会话会从该消息点开始，保留之前的上下文</li></ol><hr><h2 id="改进-ripgrep-搜索跟随符号链接" tabindex="-1">改进：ripgrep 搜索跟随符号链接 <a class="header-anchor" href="#改进-ripgrep-搜索跟随符号链接" aria-label="Permalink to “改进：ripgrep 搜索跟随符号链接”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用 Grep 工具搜索代码时，如果项目中有<strong>符号链接</strong>（symlink）指向其他目录，这些目录中的文件不会被搜索到。</p><p>常见场景：</p><ul><li>monorepo 中的共享包</li><li>node_modules 中的链接包</li><li>自定义的目录软链接</li></ul><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>OpenCode 的 ripgrep 搜索现在<strong>默认跟随符号链接</strong>：</p><ul><li>✅ 符号链接目录中的文件会被搜索</li><li>✅ 搜索结果更完整</li><li>✅ 无需额外配置</li></ul><hr><h2 id="其他改进" tabindex="-1">其他改进 <a class="header-anchor" href="#其他改进" aria-label="Permalink to “其他改进”">​</a></h2><h3 id="命令面板修复" tabindex="-1">命令面板修复 <a class="header-anchor" href="#命令面板修复" aria-label="Permalink to “命令面板修复”">​</a></h3><p>之前在 TUI 中使用命令面板时，鼠标悬停可能会高亮错误的选项。现在已修复，鼠标和键盘操作都能正确响应。</p><h3 id="提示输入自动补全" tabindex="-1">提示输入自动补全 <a class="header-anchor" href="#提示输入自动补全" aria-label="Permalink to “提示输入自动补全”">​</a></h3><p>桌面版的提示输入框现在支持：</p><ul><li>鼠标悬停预览补全选项</li><li>点击直接选择补全项</li></ul><h3 id="openai-business-支持" tabindex="-1">OpenAI Business 支持 <a class="header-anchor" href="#openai-business-支持" aria-label="Permalink to “OpenAI Business 支持”">​</a></h3><p><code>/connect</code> 命令现在完整支持 OpenAI Business 计划，解决了之前部分字段缺失的问题。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用桌面版</td><td>✅ 升级，体验会话分叉</td></tr><tr><td>项目有符号链接</td><td>✅ 升级，搜索更完整</td></tr><tr><td>使用 OpenAI Business</td><td>✅ 升级，/connect 更稳定</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',35),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>Codex 内置插件始终可用</li><li><code>/connect</code> 支持 OpenAI Business 计划（添加缺失字段）</li><li>ACP 追踪文件修改（@wid4t）</li><li>传递 sessionID 到 chat.system.transform（@spoons-and-mirrors）</li><li>提取外部目录验证到共享工具函数，减少代码重复</li><li>排除 gpt-5.2-codex 的 &#39;none&#39; 变体（@Alejandro-CSt）</li><li>ripgrep 搜索默认跟随符号链接（@kdcokenny）</li><li>禁用 PHP 语言服务器遥测（@madflow）</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>修复 TUI 组件 props.ref 问题（@itsrainingmani）</li><li>修复命令面板鼠标悬停高亮错误项（@kitlangton）</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>新增会话分叉功能（@dbpolito）</li><li>提示输入自动补全支持鼠标悬停和点击（@dbpolito）</li><li>添加缺失的 StoreExt 导入，修复未使用的 mut 警告（@jerome-benoit）</li><li>修复缺失导入导致桌面版构建失败（@Leka74）</li><li>支持配置默认服务器 URL（@athal7）</li><li>移除 serverDisplayName 函数中的 split 操作（@OpeOginni）</li></ul><h3 id="社区贡献者" tabindex="-1">社区贡献者 <a class="header-anchor" href="#社区贡献者" aria-label="Permalink to “社区贡献者”">​</a></h3><p>感谢 13 位社区贡献者：@madflow、@dbpolito、@zerone0x、@OpeOginni、@athal7、@kdcokenny、@Alejandro-CSt、@Leka74、@jerome-benoit、@spoons-and-mirrors、@kitlangton、@wid4t、@itsrainingmani</p></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=l(n,[["render",o]]);export{m as __pageData,g as default};
